def get_all_products() -> list[dict]:
    return PRODUCTS

def get_product_by_sku(sku: str) -> dict | None:
    return next((p for p in PRODUCTS if p["sku"] == sku), None)

def get_products_by_category(category: str) -> list[dict]:
    return [p for p in PRODUCTS if p["category"] == category.lower()]

def get_products_by_brand(brand: str) -> list[dict]:
    return [p for p in PRODUCTS if p["brand"].lower() == brand.lower()]

def search_products(query: str) -> list[dict]:
    q = query.lower()
    return [p for p in PRODUCTS if q in p["name"].lower() or q in p["category"]
            or q in p.get("brand", "").lower()
            or any(q in f.lower() for f in p.get("features", []))]
